import { describe, it, expect } from 'vitest';
import { chromaticBuleSieve } from '../src/chromatic-bule-sieve';
import { deblurAnyImage } from '../src/deblur-any-image';

// ---- Fixtures ----------------------------------------------------------

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function makeRGB(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  const rand = lcg(seed);
  for (let i = 0; i < w * h * 3; i++) out[i] = rand();
  return out;
}

function makeGreyRGB(w: number, h: number, seed: number): Float32Array {
  // R=G=B per pixel. Random greyscale — should round-trip CMYK without drift.
  const out = new Float32Array(w * h * 3);
  const rand = lcg(seed);
  for (let i = 0; i < w * h; i++) {
    const v = rand();
    out[i * 3] = v;
    out[i * 3 + 1] = v;
    out[i * 3 + 2] = v;
  }
  return out;
}

function constRGB(w: number, h: number, r: number, g: number, b: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  for (let i = 0; i < w * h; i++) {
    out[i * 3] = r;
    out[i * 3 + 1] = g;
    out[i * 3 + 2] = b;
  }
  return out;
}

function rmse(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) throw new Error('rmse length mismatch');
  let sum = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i] - b[i];
    sum += d * d;
  }
  return Math.sqrt(sum / a.length);
}

// ---- Tests -------------------------------------------------------------

describe('chromaticBuleSieve', () => {
  it('greyscale input round-trips through CMYK with low RMSE vs direct deblur', async () => {
    const W = 64;
    const H = 64;
    const sigma = 0.5;
    const data = makeGreyRGB(W, H, 11);

    const sieved = await chromaticBuleSieve({
      data,
      width: W,
      height: H,
      options: { sigma },
    });

    // Pull the greyscale plane (R==G==B) and deblur directly as 1-channel.
    const grey = new Float32Array(W * H);
    for (let i = 0; i < W * H; i++) grey[i] = data[i * 3];

    const direct = await deblurAnyImage(
      { data: grey, width: W, height: H, channels: 1 },
      { sigma, channelMode: 'luminance' },
    );

    // Lift the direct grey recovery into RGB for comparison.
    const directRgb = new Float32Array(W * H * 3);
    for (let i = 0; i < W * H; i++) {
      directRgb[i * 3] = direct.recovered[i];
      directRgb[i * 3 + 1] = direct.recovered[i];
      directRgb[i * 3 + 2] = direct.recovered[i];
    }

    // CMYK→RGB conversion has small float drift. The two should be close.
    const err = rmse(sieved.recovered, directRgb);
    expect(err).toBeLessThan(0.05);
  });

  it('returns the correct output shape', async () => {
    const W = 16;
    const H = 16;
    const data = makeRGB(W, H, 7);
    const result = await chromaticBuleSieve({ data, width: W, height: H, options: { sigma: 0.5 } });

    expect(result.recovered.length).toBe(W * H * 3);
    expect(result.cells.length).toBe(9);
    expect(result.channelSigmas.c).toBeGreaterThan(0);
    expect(result.channelSigmas.m).toBeGreaterThan(0);
    expect(result.channelSigmas.y).toBeGreaterThan(0);
    expect(result.channelSigmas.k).toBeGreaterThan(0);
    expect(result.width).toBe(W);
    expect(result.height).toBe(H);
  });

  it('cells partition all pixels exactly once', async () => {
    const W = 16;
    const H = 16;
    // We don't get cellCounts back, so reconstruct the partition from the
    // formula and verify every cell is visited at least once and the total
    // is W*H. The partition is independent of the data; the result need
    // only run for the test invariants further down.
    const data = makeRGB(W, H, 3);
    const result = await chromaticBuleSieve({ data, width: W, height: H, options: { sigma: 0.5 } });
    expect(result.cells.length).toBe(9);

    const counts = new Array<number>(9).fill(0);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const cell = (x + 3 * y) % 9;
        counts[cell]++;
      }
    }
    let sum = 0;
    for (let c = 0; c < 9; c++) {
      expect(counts[c]).toBeGreaterThan(0);
      sum += counts[c];
    }
    expect(sum).toBe(W * H);
  });

  it('all-black input gives near-zero CMY and near-zero output', async () => {
    const W = 16;
    const H = 16;
    const data = constRGB(W, H, 0, 0, 0);
    const result = await chromaticBuleSieve({ data, width: W, height: H, options: { sigma: 0.5 } });

    // Output should be near-black RGB.
    let maxAbs = 0;
    for (let i = 0; i < result.recovered.length; i++) {
      const v = Math.abs(result.recovered[i]);
      if (v > maxAbs) maxAbs = v;
    }
    expect(maxAbs).toBeLessThan(0.05);
  });

  it('all-white input gives K=0 and near-white output', async () => {
    const W = 16;
    const H = 16;
    const data = constRGB(W, H, 1, 1, 1);
    const result = await chromaticBuleSieve({ data, width: W, height: H, options: { sigma: 0.5 } });

    // Output should be near-white RGB. Wiener regularization can push
    // values slightly outside [0,1], so we test proximity to 1.
    let maxErr = 0;
    for (let i = 0; i < result.recovered.length; i++) {
      const e = Math.abs(result.recovered[i] - 1);
      if (e > maxErr) maxErr = e;
    }
    expect(maxErr).toBeLessThan(0.1);
  });

  it('throws on bad data length', async () => {
    const W = 8;
    const H = 8;
    const bad = new Float32Array(W * H * 3 - 5);
    await expect(
      chromaticBuleSieve({ data: bad, width: W, height: H }),
    ).rejects.toThrow(RangeError);
  });

  it('throws on non-positive width', async () => {
    const data = new Float32Array(0);
    await expect(
      chromaticBuleSieve({ data, width: 0, height: 8 }),
    ).rejects.toThrow(RangeError);
  });

  it('throws on non-positive height', async () => {
    const data = new Float32Array(0);
    await expect(
      chromaticBuleSieve({ data, width: 8, height: 0 }),
    ).rejects.toThrow(RangeError);
  });

  it('throws on bad channelRejections length', async () => {
    const W = 8;
    const H = 8;
    const data = makeRGB(W, H, 1);
    await expect(
      chromaticBuleSieve({
        data,
        width: W,
        height: H,
        channelRejections: [0, 0, 0], // wrong length
      }),
    ).rejects.toThrow(RangeError);
  });

  it('metabolism is non-negative for every cell × channel', async () => {
    const W = 16;
    const H = 16;
    const data = makeRGB(W, H, 5);
    const result = await chromaticBuleSieve({ data, width: W, height: H, options: { sigma: 0.5 } });

    for (const cell of result.cells) {
      expect(cell.metabolism.c).toBeGreaterThanOrEqual(0);
      expect(cell.metabolism.m).toBeGreaterThanOrEqual(0);
      expect(cell.metabolism.y).toBeGreaterThanOrEqual(0);
      expect(cell.metabolism.k).toBeGreaterThanOrEqual(0);
    }
  });

  it('per-cell Buleyean weights stay sum-bounded in [4, 20]', async () => {
    // With R=4 channels and v ∈ {0,1,2,3} (distinct ranks), the weights
    // are buleyeanWeight(4, v) = 4 - v + 1 = 5,4,3,2 → sum = 14 when all
    // ranks distinct and channelRejections=0. Spec gives a worst-case
    // upper bound 4*5 = 20 (all rank 0 with rejections 0). Lower bound
    // is 4 when v ≥ R for every channel.
    const W = 16;
    const H = 16;
    const data = makeRGB(W, H, 9);
    const result = await chromaticBuleSieve({ data, width: W, height: H, options: { sigma: 0.5 } });

    for (const cell of result.cells) {
      const sumW =
        cell.weights.c + cell.weights.m + cell.weights.y + cell.weights.k;
      expect(sumW).toBeLessThanOrEqual(20);
      expect(sumW).toBeGreaterThanOrEqual(4);
    }
  });
});
